#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
typedef long long ll;
const int N=5010;
ll dp[N][N],x[N],a[N],b[N],c[N],d[N];int n,s,t;
inline void In(ll *a){rep(1,n,i)a[i]=read();}
inline void Ou(ll *a)
{
	printf("qwq :: ");rep(1,n,i)printf("%lld ",a[i]);puts("");
	}
int main()
{
//	FIN("data.in");
//	FOUT("mine.out");
	n=read();s=read();t=read();
	In(x);In(a);In(b);In(c);In(d);
	memset(dp,0x3f,sizeof(dp));dp[1][1]=0;
	
	rep(1,n,i)a[i]+=x[i],b[i]-=x[i],c[i]+=x[i],d[i]-=x[i];
//	Ou(a);Ou(b);Ou(c);Ou(d);
	if(s!=1)dp[1][1]+=b[1];
	if(t!=1)dp[1][1]+=d[1];
	rep(1,n-1,i)
	{
		rep((i+1>s)+(i+1>t),i,j)
		{
			if(i+1==s)
			{
				dp[s][j]=min(dp[s][j],dp[i][j]+c[s]);
				dp[s][j+1]=min(dp[s][j+1],dp[i][j]+d[s]);
			}
			else if(i+1==t)
			{
				dp[t][j]=min(dp[t][j],dp[i][j]+a[t]);
				dp[t][j+1]=min(dp[t][j+1],dp[i][j]+b[t]);
			}
			else
			{
				dp[i+1][j+1]=min(dp[i+1][j+1],dp[i][j]+b[i+1]+d[i+1]);
//				printf("(%d,%d) --> (%d,%d) %lld %lld %lld %lld\n",i,j,i+1,j+1,dp[i+1][j+1],dp[i][j],b[i+1],d[i+1]);
				if(!(i+1>s&&j==1))
					dp[i+1][j]=min(dp[i+1][j],dp[i][j]+b[i+1]+c[i+1]);//,printf("(%d,%d) --> (%d,%d) %d\n",i,j,i+1,j,dp[i+1][j]);;
				if(!(i+1>t&&j==1))
					dp[i+1][j]=min(dp[i+1][j],dp[i][j]+a[i+1]+d[i+1]);//,printf("(%d,%d) --> (%d,%d) %d\n",i,j,i+1,j,dp[i+1][j]);;
				if(j!=1)
					dp[i+1][j-1]=min(dp[i+1][j-1],dp[i][j]+a[i+1]+c[i+1]);//,printf("(%d,%d) --> (%d,%d) %d\n",i,j,i+1,j-1,dp[i+1][j-1]);;
			}
		}
	}
//	rep(1,n,i)
//	{
//		rep(1,n,j)printf("%lld ",dp[i][j]>10000?-1ll:dp[i][j]);
//		puts("");	
//	}
	printf("%lld\n",dp[n][1]);return 0;
}
